function tar(e){let t=[];for(let[n,r]of Object.entries(e)){let a=new TextEncoder().encode(r),o=new TextEncoder().encode(n),s=new Uint8Array(512);s.set(o.slice(0,100),0);let l="0000644";for(let e=0;e<7;e++)s[100+e]=l.charCodeAt(e);let c=a.length.toString(8).padStart(11,"0")+"\0";for(let e=0;e<12;e++)s[124+e]=c.charCodeAt(e);let u="ustar";for(let e=0;e<5;e++)s[257+e]=u.charCodeAt(e);s[262]=0;for(let e=148;e<156;e++)s[e]=32;let d=0;for(let e=0;e<512;e++)d+=s[e];let p=d.toString(8).padStart(6,"0")+"\0";for(let e=0;e<7;e++)s[148+e]=p.charCodeAt(e);s[155]=0;t.push(s);if(a.length>0){t.push(a);let e=(512-a.length%512)%512;e>0&&t.push(new Uint8Array(e))}}t.push(new Uint8Array(1024));let n=t.reduce((e,t)=>e+t.length,0),r=new Uint8Array(n),a=0;for(let e of t)r.set(e,a),a+=e.length;return r}
function gzipCompress(e){return typeof pako!="undefined"?pako.gzip(e):(console.warn("pako not loaded — returning uncompressed tar"),e)}
